#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 4e5+5;
ULL n,m,od[N],Q,inf;
ULL tr[N],ans[N];
vector<int> bel[N];
struct node{
    ULL wan,id;
}q[N],q1[N],q2[N];
struct Rain{
    ULL x,id,val;
}rai[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void upd(int x,ULL k){while(x<=m)tr[x]+=k,x+=x&-x;return;}
ULL ask(int x){ULL sum=0;while(x)sum+=tr[x],x-=x&-x;return sum;}
void solve(int l,int r,int L,int R){
    //cout<<"quest ";
    //for(int i=L;i<=R;i++)cout<<q[i].id<<" ";
    //cout<<"'s answer in ["<<l<<","<<r<<"]\n";
    if(L>R)return;
    if(l==r){
        for(int i=L;i<=R;i++)ans[q[i].id]=l;
        return;
    }
    int mid=(l+r)>>1,p1=0,p2=0;
    for(int i=l;i<=mid;i++){
        if(i==Q)break;
        auto [ll,rr,kk]=rai[i];
        //cout<<"down RAIN["<<ll<<","<<rr<<"]"<<kk<<"\n";
        if(ll<=rr)upd(ll,kk),upd(rr+1,-kk);
        else upd(1,kk),upd(rr+1,-kk),upd(ll,kk);
    }
    for(int i=L;i<=R;i++){
        LL tmp=0;
        for(int x:bel[q[i].id])tmp+=ask(x);
        //cout<<"now "<<q[i].id<<" hav "<<tmp<<" and need "<<q[i].wan<<"\n";
        if(tmp>=q[i].wan)q1[++p1]=q[i];
        else q[i].wan-=tmp,q2[++p2]=q[i];
    }
    for(int i=1;i<=p1;i++)q[L+i-1]=q1[i];
    for(int i=1;i<=p2;i++)q[R-p2+i]=q2[i];
    for(int i=l;i<=mid;i++){
        auto [ll,rr,kk]=rai[i];
        if(ll<=rr)upd(ll,-kk),upd(rr+1,kk);
        else upd(1,-kk),upd(rr+1,kk),upd(ll,-kk);
    }
    solve(l,mid,L,L+p1-1);
    solve(mid+1,r,R-p2+1,R);return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=m;i++)
        od[i]=read(),bel[od[i]].pb(i);
    for(int i=1;i<=n;i++)
        q[i].wan=read(),q[i].id=i,
        inf=max(inf,q[i].wan);
    Q=read();
    for(int i=1;i<=Q;i++){
        int l=read(),r=read();
        LL k=read();
        rai[i]={l,r,k};
    }
    rai[++Q]={1,m,inf};
    solve(1,Q,1,n);
    for(int i=1;i<=n;i++)
        if(ans[i]<Q)cout<<ans[i]<<"\n";
        else cout<<"NIE\n";
    return 0;
}
